function RazorPay({amount}) {

    const phonePrice = 67999;
    const laptopPrice = 125000;
    var formatter = new Intl.NumberFormat("en-US", {
        style: "currency",
        currency: "INR",

        // These options are needed to round to whole numbers if that's what you want.
        minimumFractionDigits: 0, // (this suffices for whole numbers, but will print 2500.10 as $2,500.1)
        //maximumFractionDigits: 0, // (causes 2500.99 to be printed as $2,501)
    });

    const loadScript = (src) => {
        return new Promise((resovle) => {
            const script = document.createElement("script");
            script.src = src;

            script.onload = () => {
                resovle(true);
            };

            script.onerror = () => {
                resovle(false);
            };

            document.body.appendChild(script);
        });
    };

    const displayRazorpay = async (amount) => {
        const res = await loadScript(
            "https://checkout.razorpay.com/v1/checkout.js"
        );

        if (!res) {
            alert("You are offline... Failed to load Razorpay SDK");
            return;
        }

        const options = {
            key: "rzp_test_VdGdvprTKB8u1w",
            currency: "INR",
            amount: amount * 100,
            name: "Universal Traders",
            description: "Thanks for purchasing",
            image:
                "",

            handler: function (response) {
                alert(response.razorpay_payment_id);
                alert("Payment Successfully");
            },
            prefill: {
                name: "",
            },
        };

        const paymentObject = new window.Razorpay(options);
        paymentObject.open();
    };
    return (
        <div className="App">
            <div className="product">
                <>
                    <div className="prod-container">
                        <h1 style={{textAlign: 'center',marginTop: '10vh'}}>Are you sure you want to pay <span style={{color: 'red'}}>{ formatter.format(amount)}</span><br /> to Universal Traders <span style={{color: 'blue'}}><br />via RazorPay</span></h1>
                        <div className="buttons" style={{display: 'flex',justifyContent: 'center'}}>
                            <button style={{padding: '10px 40px'}} className="pay-btn" onClick={() => displayRazorpay(amount)}>
                                PAY NOW
                            </button>
                        </div>
                    </div>
                </>
            </div>
        </div>
    )
}

export default RazorPay